import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a matrix?", a: "A matrix is a rectangular grid of numbers arranged in rows and columns. Matrices are used in algebra, graphics, engineering, statistics, and systems of equations." },
  { q: "How do you multiply two matrices?", a: "To multiply matrices, take each row of the first matrix and each column of the second matrix, multiply matching entries, and add the products." },
  { q: "What is the determinant of a matrix?", a: "The determinant is a special value calculated from a square matrix. It helps determine whether a matrix is invertible and is used in solving systems of equations." },
  { q: "What is the transpose of a matrix?", a: "The transpose flips a matrix over its diagonal, turning rows into columns and columns into rows." },
  { q: "When can you add or subtract two matrices?", a: "Matrices can be added or subtracted only when they have the same dimensions. This calculator supports matching 2x2 and 3x3 matrices." },
];

type Size = 2 | 3;
type Op = "add" | "subtract" | "multiply" | "transpose" | "determinant";
type Matrix = number[][];
const baseA = [[1, 2, 3], [4, 5, 6], [7, 8, 10]];
const baseB = [[2, 0, 1], [1, 3, 2], [4, 1, 0]];
const fmt = (n: number) => Number.isFinite(n) ? Number(n.toFixed(4)).toLocaleString() : "Invalid";
const det = (m: Matrix, size: Size) => size === 2 ? m[0][0] * m[1][1] - m[0][1] * m[1][0] : m[0][0] * (m[1][1] * m[2][2] - m[1][2] * m[2][1]) - m[0][1] * (m[1][0] * m[2][2] - m[1][2] * m[2][0]) + m[0][2] * (m[1][0] * m[2][1] - m[1][1] * m[2][0]);

export default function MatrixCalculator() {
  const [size, setSize] = useState<Size>(2);
  const [op, setOp] = useState<Op>("add");
  const [a, setA] = useState<Matrix>(baseA);
  const [b, setB] = useState<Matrix>(baseB);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  const setCell = (which: "a" | "b", r: number, c: number, value: number) => {
    const setter = which === "a" ? setA : setB;
    const current = which === "a" ? a : b;
    setter(current.map((row, ri) => row.map((cell, ci) => ri === r && ci === c ? value : cell)));
  };

  const result = useMemo(() => {
    const A = a.slice(0, size).map((row) => row.slice(0, size));
    const B = b.slice(0, size).map((row) => row.slice(0, size));
    if (op === "determinant") return { matrix: [[det(A, size)]], step: `det(A) = ${fmt(det(A, size))}.` };
    if (op === "transpose") return { matrix: A[0].map((_, c) => A.map((row) => row[c])), step: "Transpose swaps rows and columns of Matrix A." };
    if (op === "multiply") {
      const m = A.map((row, r) => row.map((_, c) => row.reduce((sum, val, k) => sum + val * B[k][c], 0)));
      return { matrix: m, step: "Each result cell is the dot product of a row from A and a column from B." };
    }
    const m = A.map((row, r) => row.map((val, c) => op === "add" ? val + B[r][c] : val - B[r][c]));
    return { matrix: m, step: op === "add" ? "Add matching cells from A and B." : "Subtract matching cells in B from A." };
  }, [a, b, size, op]);

  const grid = (which: "a" | "b", matrix: Matrix) => <div className={`grid gap-2 ${size === 2 ? "grid-cols-2" : "grid-cols-3"}`}>{Array.from({ length: size }).map((_, r) => Array.from({ length: size }).map((__, c) => <input key={`${which}-${r}-${c}`} type="number" value={matrix[r][c]} onChange={(event) => setCell(which, r, c, Number(event.target.value))} className="w-full px-2 py-2 rounded-lg border border-input bg-background text-center font-bold text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />))}</div>;

  return (
    <>
      <SEOHead title="Free Matrix Calculator Online - Add Subtract Multiply and Find Determinant Instantly | CalcHive" description="Free online matrix calculator. Perform matrix addition, subtraction, multiplication, transpose and find determinant for 2x2 and 3x3 matrices instantly. 100% free for students, no signup required." canonical="/matrix-calculator" keywords="free matrix calculator, matrix calculator online free, 2x2 matrix calculator free, matrix determinant calculator free, matrix multiplication calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Matrix Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free matrix calculator to add, subtract, multiply, transpose, and find determinants for 2x2 and 3x3 matrices.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Matrix size</label><select value={size} onChange={(event) => setSize(Number(event.target.value) as Size)} className={inputClass}><option value={2}>2x2</option><option value={3}>3x3</option></select></div><div><label className="text-sm font-semibold text-foreground block mb-2">Operation</label><select value={op} onChange={(event) => setOp(event.target.value as Op)} className={inputClass}><option value="add">Add</option><option value="subtract">Subtract</option><option value="multiply">Multiply</option><option value="transpose">Transpose A</option><option value="determinant">Determinant of A</option></select></div></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 mb-8"><div><h2 className="text-lg font-bold text-foreground mb-3">Matrix A</h2>{grid("a", a)}</div>{op !== "transpose" && op !== "determinant" && <div><h2 className="text-lg font-bold text-foreground mb-3">Matrix B</h2>{grid("b", b)}</div>}</div>
          <motion.div key={`${size}-${op}-${JSON.stringify(a)}-${JSON.stringify(b)}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-3">Result</p><div data-testid="result-matrix" className={`mx-auto grid gap-2 max-w-xs ${result.matrix[0].length === 1 ? "grid-cols-1" : result.matrix[0].length === 2 ? "grid-cols-2" : "grid-cols-3"}`}>{result.matrix.flat().map((v, i) => <span key={i} className="bg-white/15 rounded-lg px-3 py-2 text-white font-black">{fmt(v)}</span>)}</div></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Add Subtract and Multiply Matrices for Free</h2><p className="text-muted-foreground leading-relaxed">Enter 2x2 or 3x3 matrices and choose an operation. This matrix multiplication calculator free online performs the operation instantly.</p><h2 className="text-2xl font-bold text-foreground">How to Calculate the Determinant of a Matrix</h2><p className="text-muted-foreground leading-relaxed">For 2x2 matrices, determinant is ad - bc. For 3x3 matrices, this calculator expands across the first row.</p><h2 className="text-2xl font-bold text-foreground">Free Linear Algebra Matrix Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this 2x2 matrix calculator free and matrix determinant calculator free for algebra, linear systems, and homework checks.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/matrix-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


